"""A shopping cart with item management and discount support.

This module exposes a :class:`ShoppingCart` that tracks line items, computes
subtotals and totals, and applies either a percentage or a flat discount.
All monetary values are handled with :class:`decimal.Decimal` to avoid the
rounding errors inherent in binary floating-point arithmetic.
"""

from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal, ROUND_HALF_UP


CENTS = Decimal("0.01")


class ShoppingCartError(Exception):
    """Base class for all shopping cart errors."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an operation references a product not in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(f"No item named {product_name!r} exists in the cart.")
        self.product_name = product_name


class DuplicateItemError(ShoppingCartError):
    """Raised when adding a product that is already in the cart."""

    def __init__(self, product_name: str) -> None:
        super().__init__(
            f"Item {product_name!r} is already in the cart; "
            f"update its quantity instead of adding it again."
        )
        self.product_name = product_name


class InvalidQuantityError(ShoppingCartError):
    """Raised when a quantity is not a positive integer."""

    def __init__(self, quantity: int) -> None:
        super().__init__(f"Quantity must be a positive integer, got {quantity!r}.")
        self.quantity = quantity


class InvalidPriceError(ShoppingCartError):
    """Raised when a unit price is negative."""

    def __init__(self, unit_price: Decimal) -> None:
        super().__init__(f"Unit price must not be negative, got {unit_price!r}.")
        self.unit_price = unit_price


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount value is outside its valid range."""

    def __init__(self, message: str) -> None:
        super().__init__(message)


@dataclass(frozen=True)
class CartItem:
    """A single line item in the cart.

    Instances are immutable; quantity changes produce a new instance via
    :meth:`with_quantity`, which keeps the cart's state transitions explicit.
    """

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the cost of this line (unit price times quantity)."""
        return self.unit_price * self.quantity

    def with_quantity(self, quantity: int) -> "CartItem":
        """Return a copy of this item with a different quantity."""
        return CartItem(self.product_name, self.unit_price, quantity)


class ShoppingCart:
    """An in-memory shopping cart supporting discounts.

    The cart stores at most one line item per product name. Prices are
    normalized to :class:`~decimal.Decimal` on entry, and all returned
    monetary amounts are rounded to two decimal places using half-up rounding.
    """

    def __init__(self) -> None:
        """Create an empty cart."""
        self._items: dict[str, CartItem] = {}

    def add_item(
        self,
        product_name: str,
        unit_price: Decimal | str | int | float,
        quantity: int,
    ) -> CartItem:
        """Add a new item to the cart and return it.

        Raises:
            DuplicateItemError: If the product is already in the cart.
            InvalidPriceError: If ``unit_price`` is negative.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        if product_name in self._items:
            raise DuplicateItemError(product_name)

        price = self._normalize_price(unit_price)
        self._validate_quantity(quantity)

        item = CartItem(product_name, price, quantity)
        self._items[product_name] = item
        return item

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
        """
        self._require_item(product_name)
        del self._items[product_name]

    def update_quantity(self, product_name: str, quantity: int) -> CartItem:
        """Set the quantity of an existing item and return the updated item.

        Raises:
            ItemNotFoundError: If the product is not in the cart.
            InvalidQuantityError: If ``quantity`` is not a positive integer.
        """
        existing_item = self._require_item(product_name)
        self._validate_quantity(quantity)

        updated_item = existing_item.with_quantity(quantity)
        self._items[product_name] = updated_item
        return updated_item

    def subtotal(self) -> Decimal:
        """Return the total cost of all items before any discount."""
        total = sum((item.line_total for item in self._items.values()), Decimal(0))
        return self._to_currency(total)

    def total_with_percentage_discount(
        self, percentage: Decimal | str | int
    ) -> Decimal:
        """Return the total after applying a percentage discount.

        Args:
            percentage: A value in the inclusive range ``0``–``100``.

        Raises:
            InvalidDiscountError: If ``percentage`` is outside ``0``–``100``.
        """
        rate = Decimal(str(percentage))
        if not Decimal(0) <= rate <= Decimal(100):
            raise InvalidDiscountError(
                f"Percentage discount must be between 0 and 100, got {percentage!r}."
            )

        discount = self.subtotal() * rate / Decimal(100)
        return self._apply_discount(discount)

    def total_with_flat_discount(
        self, amount: Decimal | str | int | float
    ) -> Decimal:
        """Return the total after subtracting a flat discount amount.

        Args:
            amount: A non-negative amount not exceeding the subtotal.

        Raises:
            InvalidDiscountError: If ``amount`` is negative or exceeds the subtotal.
        """
        discount = self._normalize_price(amount, error=InvalidDiscountError)
        if discount > self.subtotal():
            raise InvalidDiscountError(
                f"Flat discount {discount!r} exceeds subtotal {self.subtotal()!r}."
            )

        return self._apply_discount(discount)

    def items(self) -> list[CartItem]:
        """Return all items in the cart in insertion order."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items from the cart."""
        self._items.clear()

    def __len__(self) -> int:
        """Return the number of distinct items in the cart."""
        return len(self._items)

    def __contains__(self, product_name: object) -> bool:
        """Return whether a product name is in the cart."""
        return product_name in self._items

    def _apply_discount(self, discount: Decimal) -> Decimal:
        """Subtract a validated discount from the subtotal and round it."""
        return self._to_currency(self.subtotal() - discount)

    def _require_item(self, product_name: str) -> CartItem:
        """Return an item or raise if it is absent."""
        try:
            return self._items[product_name]
        except KeyError:
            raise ItemNotFoundError(product_name) from None

    @staticmethod
    def _normalize_price(
        unit_price: Decimal | str | int | float,
        error: type[ShoppingCartError] = InvalidPriceError,
    ) -> Decimal:
        """Coerce a price-like value to ``Decimal`` and reject negatives."""
        price = Decimal(str(unit_price))
        if price < 0:
            raise error(price)
        return price

    @staticmethod
    def _validate_quantity(quantity: int) -> None:
        """Reject quantities that are not positive integers."""
        if not isinstance(quantity, int) or isinstance(quantity, bool) or quantity <= 0:
            raise InvalidQuantityError(quantity)

    @staticmethod
    def _to_currency(amount: Decimal) -> Decimal:
        """Round a monetary amount to two decimal places, half up."""
        return amount.quantize(CENTS, rounding=ROUND_HALF_UP)
```

## Design notes

- **Data structure:** `CartItem` is a frozen `dataclass` with a derived `line_total` property. Immutability means quantity updates go through `with_quantity`, making every state change in the cart explicit rather than mutating shared objects.
- **SRP:** Each public method does exactly one thing. Validation (`_validate_quantity`, `_normalize_price`), lookup (`_require_item`), discount application (`_apply_discount`), and rounding (`_to_currency`) are isolated helpers.
- **DRY:** Both discount methods funnel through `_apply_discount`; both prices/discounts share `_normalize_price` (parameterized by exception type); all monetary output flows through `_to_currency`.
- **Exceptions:** A `ShoppingCartError` hierarchy with specific subclasses carrying structured attributes — no bare `ValueError`/`Exception`.
- **Money correctness:** `Decimal` throughout, constructed via `str()` to avoid inheriting float imprecision, with `ROUND_HALF_UP` quantization. The `bool` check in `_validate_quantity` guards against `True`/`False` sneaking through as `int`.
- **No side effects:** Every method returns values; no prints. The mutable state (`_items`) is created per-instance in `__init__`, so there are no mutable default arguments.

A couple of design choices worth flagging in review: I chose a one-line-per-product model (re-adding raises `DuplicateItemError` rather than merging), and discounts are computed on demand rather than stored as cart state — keeping the cart a pure source of truth. If you'd prefer add-to-merge semantics or stored/stacked discounts, those are easy adjustments.

