from __future__ import annotations

from dataclasses import dataclass
from decimal import Decimal, InvalidOperation
from typing import Protocol


class ShoppingCartError(Exception):
    """Base exception for shopping cart errors."""


class InvalidProductNameError(ShoppingCartError):
    """Raised when a product name is empty or invalid."""


class InvalidPriceError(ShoppingCartError):
    """Raised when a product price is invalid."""


class InvalidQuantityError(ShoppingCartError):
    """Raised when an item quantity is invalid."""


class ItemNotFoundError(ShoppingCartError):
    """Raised when an item is not found in the cart."""


class InvalidDiscountError(ShoppingCartError):
    """Raised when a discount is invalid."""


@dataclass(frozen=True, slots=True)
class CartItem:
    """Represents a single item in a shopping cart."""

    product_name: str
    unit_price: Decimal
    quantity: int

    @property
    def line_total(self) -> Decimal:
        """Return the total price for this cart item."""
        return self.unit_price * self.quantity


class Discount(Protocol):
    """Defines the interface for cart discounts."""

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return the discount amount for the given subtotal."""
        ...


@dataclass(frozen=True, slots=True)
class PercentageDiscount:
    """Represents a percentage-based discount."""

    percentage: Decimal

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return the percentage discount amount for the given subtotal."""
        return subtotal * (self.percentage / Decimal("100"))


@dataclass(frozen=True, slots=True)
class FlatDiscount:
    """Represents a fixed-amount discount."""

    amount: Decimal

    def apply(self, subtotal: Decimal) -> Decimal:
        """Return the flat discount amount for the given subtotal."""
        return min(self.amount, subtotal)


class ShoppingCart:
    """Manages cart items, discounts, and cart total calculations."""

    def __init__(self) -> None:
        self._items: dict[str, CartItem] = {}
        self._discount: Discount | None = None

    def add_item(self, product_name: str, unit_price: Decimal, quantity: int = 1) -> None:
        """Add an item to the cart or increase its quantity if it already exists."""
        normalized_name = self._validate_product_name(product_name)
        validated_price = self._validate_money(unit_price, "unit price")
        validated_quantity = self._validate_quantity(quantity)

        existing_item = self._items.get(normalized_name)
        if existing_item is None:
            self._items[normalized_name] = CartItem(
                product_name=normalized_name,
                unit_price=validated_price,
                quantity=validated_quantity,
            )
            return

        self._items[normalized_name] = CartItem(
            product_name=normalized_name,
            unit_price=validated_price,
            quantity=existing_item.quantity + validated_quantity,
        )

    def remove_item(self, product_name: str) -> None:
        """Remove an item from the cart by product name."""
        normalized_name = self._validate_product_name(product_name)
        self._get_existing_item(normalized_name)
        del self._items[normalized_name]

    def update_quantity(self, product_name: str, quantity: int) -> None:
        """Update the quantity of an existing cart item."""
        normalized_name = self._validate_product_name(product_name)
        validated_quantity = self._validate_quantity(quantity)
        existing_item = self._get_existing_item(normalized_name)

        self._items[normalized_name] = CartItem(
            product_name=existing_item.product_name,
            unit_price=existing_item.unit_price,
            quantity=validated_quantity,
        )

    def calculate_subtotal(self) -> Decimal:
        """Return the cart subtotal before discounts."""
        return sum((item.line_total for item in self._items.values()), Decimal("0"))

    def apply_percentage_discount(self, percentage: Decimal) -> None:
        """Apply a percentage discount to the cart."""
        validated_percentage = self._validate_percentage_discount(percentage)
        self._discount = PercentageDiscount(validated_percentage)

    def apply_flat_discount(self, amount: Decimal) -> None:
        """Apply a flat discount amount to the cart."""
        validated_amount = self._validate_money(amount, "flat discount")
        self._discount = FlatDiscount(validated_amount)

    def clear_discount(self) -> None:
        """Remove any active discount from the cart."""
        self._discount = None

    def calculate_total(self) -> Decimal:
        """Return the cart total after applying any active discount."""
        subtotal = self.calculate_subtotal()

        if self._discount is None:
            return subtotal

        discount_amount = self._discount.apply(subtotal)
        return max(subtotal - discount_amount, Decimal("0"))

    def list_items(self) -> list[CartItem]:
        """Return all cart items with their product name, unit price, quantity, and line total."""
        return list(self._items.values())

    def clear(self) -> None:
        """Remove all items and discounts from the cart."""
        self._items.clear()
        self._discount = None

    def _get_existing_item(self, product_name: str) -> CartItem:
        if product_name not in self._items:
            raise ItemNotFoundError(f"Product '{product_name}' was not found in the cart.")

        return self._items[product_name]

    @staticmethod
    def _validate_product_name(product_name: str) -> str:
        if not isinstance(product_name, str):
            raise InvalidProductNameError("Product name must be a string.")

        normalized_name = product_name.strip()
        if not normalized_name:
            raise InvalidProductNameError("Product name cannot be empty or whitespace.")

        return normalized_name

    @staticmethod
    def _validate_quantity(quantity: int) -> int:
        if isinstance(quantity, bool) or not isinstance(quantity, int):
            raise InvalidQuantityError("Quantity must be an integer.")

        if quantity <= 0:
            raise InvalidQuantityError("Quantity must be greater than zero.")

        return quantity

    @staticmethod
    def _validate_money(amount: Decimal, field_name: str) -> Decimal:
        try:
            validated_amount = Decimal(amount)
        except (InvalidOperation, TypeError) as error:
            raise InvalidPriceError(f"{field_name.capitalize()} must be a valid decimal amount.") from error

        if validated_amount < Decimal("0"):
            raise InvalidPriceError(f"{field_name.capitalize()} cannot be negative.")

        return validated_amount

    @staticmethod
    def _validate_percentage_discount(percentage: Decimal) -> Decimal:
        try:
            validated_percentage = Decimal(percentage)
        except (InvalidOperation, TypeError) as error:
            raise InvalidDiscountError("Percentage discount must be a valid decimal amount.") from error

        if validated_percentage < Decimal("0") or validated_percentage > Decimal("100"):
            raise InvalidDiscountError("Percentage discount must be between 0 and 100.")

        return validated_percentage
